/** Lookup a move by name (case-insensitive) */
export function getMoveByName(name: string): Move | undefined {
  return MOVES.find(m => m.name.toLowerCase() === name.toLowerCase().trim());
}

/** Search moves by partial name */
export function searchMoves(query: string): Move[] {
  const normalized = query.toLowerCase().trim();
  if (!normalized) return [];
  return MOVES.filter(m => m.name.toLowerCase().includes(normalized)).slice(0, 20);
}

/** Get all moves of a specific type */
export function getMovesByType(type: string): Move[] {
  return MOVES.filter(m => m.type.toLowerCase() === type.toLowerCase());
}

/** Get all moves a Pokemon can learn (placeholder — would need per-Pokemon learnsets) */
export function getMovesForPokemon(_pokemonName: string): Move[] {
  // In a full implementation, this would use per-Pokemon learnsets
  // For now, return a curated list of common competitive moves
  return MOVES;
}

/** Get all move names for autocomplete */
export function getAllMoveNames(): string[] {
  return MOVES.map(m => m.name);
}
